import cadquery as cq

# Parametric dimensions
size = 60.0
bar = 4.0

half = size / 2.0
inner = size - 2 * bar
center_half = inner / 2.0

def beam_x(x0, y0, z0, length=size, thickness=bar):
    return (
        cq.Workplane("YZ")
        .center(y0, z0)
        .rect(thickness, thickness)
        .extrude(length, both=True)
        .translate((x0, 0, 0))
    )

def beam_y(x0, y0, z0, length=size, thickness=bar):
    return (
        cq.Workplane("XZ")
        .center(x0, z0)
        .rect(thickness, thickness)
        .extrude(length, both=True)
        .translate((0, y0, 0))
    )

def beam_z(x0, y0, z0, length=size, thickness=bar):
    return (
        cq.Workplane("XY")
        .center(x0, y0)
        .rect(thickness, thickness)
        .extrude(length, both=True)
        .translate((0, 0, z0))
    )

parts = []

# Cube outer frame: 12 edges
